import { type LiHTMLAttributes, forwardRef } from "react";
import { clsx } from "clsx";
import * as styles from "./ListItem.css";

export interface ListItemProps extends LiHTMLAttributes<HTMLLIElement> {}

/**
 * A list item wrapper component that renders an `<li>` element.
 * Use within `<ul>` or `<ol>` elements.
 *
 * Typically contains a `ListItemInner` component for interactive content,
 * but can also contain custom content directly.
 */
export const ListItem = forwardRef<HTMLLIElement, ListItemProps>(
  ({ children, className, ...props }, ref) => {
    return (
      <li ref={ref} className={clsx(styles.listItem, className)} {...props}>
        {children}
      </li>
    );
  }
);

ListItem.displayName = "ListItem";
